// File: CollectionsDemo.java
// Run: javac CollectionsDemo.java && java CollectionsDemo
import java.util.*;
import java.util.concurrent.*;

public class CollectionsDemo {
  public static void main(String[] args) {
    // --- ArrayList — the default List ---
    List<String> list = new ArrayList<>();
    list.add("Ada"); list.add("Kim"); list.add("Bob");
    System.out.println(list.get(1));      // Kim (O(1) index)
    list.remove("Kim");
    System.out.println(list);             // [Ada, Bob]

    // --- HashSet — no duplicates ---
    Set<String> set = new HashSet<>();
    set.add("Ada"); set.add("Ada"); set.add("Bob");
    System.out.println(set.size());       // 2

    // --- HashMap — key → value ---
    Map<String, Integer> scores = new HashMap<>();
    scores.put("Ada", 90);
    scores.put("Kim", 87);
    scores.merge("Ada", 5, Integer::sum); // increment Ada's score by 5
    System.out.println(scores);           // {Ada=95, Kim=87}

    // --- TreeMap — sorted keys ---
    Map<Integer, String> byId = new TreeMap<>();
    byId.put(3, "c"); byId.put(1, "a"); byId.put(2, "b");
    System.out.println(byId);             // {1=a, 2=b, 3=c} — sorted!

    // --- LinkedHashMap — insertion order ---
    Map<String, Integer> ordered = new LinkedHashMap<>();
    ordered.put("z", 1); ordered.put("a", 2);
    System.out.println(ordered);          // {z=1, a=2} — insertion order

    // --- ArrayDeque as a stack + queue ---
    Deque<Integer> deque = new ArrayDeque<>();
    deque.push(1); deque.push(2); deque.push(3);   // stack
    System.out.println(deque.pop());               // 3 (LIFO)
    deque.offer(10); deque.offer(20);              // queue
    System.out.println(deque.poll());              // 2 (FIFO)

    // --- PriorityQueue — smallest first ---
    PriorityQueue<Integer> pq = new PriorityQueue<>();
    pq.offer(5); pq.offer(1); pq.offer(3);
    while (!pq.isEmpty()) System.out.print(pq.poll() + " ");   // 1 3 5
    System.out.println();

    // --- Common one-liners you'll write hundreds of times ---
    Map<String, Long> wordCount = Arrays.stream("the quick brown fox the lazy fox".split(" "))
        .collect(java.util.stream.Collectors.groupingBy(w -> w, java.util.stream.Collectors.counting()));
    System.out.println(wordCount);        // {quick=1, brown=1, fox=2, lazy=1, the=2}

    // --- ConcurrentHashMap for multi-threaded work ---
    Map<String, Integer> safe = new ConcurrentHashMap<>();
    safe.compute("count", (k, v) -> v == null ? 1 : v + 1);
    System.out.println(safe);             // {count=1} — safe under threads
  }
}
